const express = require('express');
const session = require('express-session');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
const PORT = process.env.PORT || 3000;

// Twilio configuration
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || 'your_account_sid';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || 'your_auth_token';
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER || '+1234567890';

const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

// In-memory store for 2FA codes
const twoFactorStore = new Map();

// Code expiration time (5 minutes)
const CODE_EXPIRATION_MS = 5 * 60 * 1000;

// Max verification attempts
const MAX_ATTEMPTS = 3;

// Rate limiting: max codes per phone number per hour
const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000;
const MAX_CODES_PER_WINDOW = 5;
const rateLimitStore = new Map();

// Simulated user database
const usersDb = new Map();
usersDb.set('user1', { id: 'user1', username: 'john_doe', phone: '+11234567890', password: 'hashed_password_1' });
usersDb.set('user2', { id: 'user2', username: 'jane_doe', phone: '+10987654321', password: 'hashed_password_2' });

// Middleware
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(session({
    secret: process.env.SESSION_SECRET || 'your-super-secret-session-key-change-in-production',
    resave: false,
    saveUninitialized: false,
    cookie: {
        secure: process.env.NODE_ENV === 'production',
        httpOnly: true,
        maxAge: 30 * 60 * 1000 // 30 minutes
    }
}));

// Generate a cryptographically secure 6-digit code
function generateCode() {
    const buffer = crypto.randomBytes(4);
    const num = buffer.readUInt32BE(0);
    const code = (num % 900000 + 100000).toString();
    return code;
}

// Check rate limiting for a phone number
function checkRateLimit(phoneNumber) {
    const now = Date.now();
    const key = phoneNumber;

    if (!rateLimitStore.has(key)) {
        rateLimitStore.set(key, []);
    }

    const timestamps = rateLimitStore.get(key).filter(ts => now - ts < RATE_LIMIT_WINDOW_MS);
    rateLimitStore.set(key, timestamps);

    if (timestamps.length >= MAX_CODES_PER_WINDOW) {
        return false;
    }

    timestamps.push(now);
    return true;
}

// Store a 2FA code for a user
function storeCode(userId, code, phoneNumber) {
    const entry = {
        code,
        phoneNumber,
        createdAt: Date.now(),
        attempts: 0,
        verified: false
    };

    twoFactorStore.set(userId, entry);

    // Auto-cleanup after expiration
    setTimeout(() => {
        const stored = twoFactorStore.get(userId);
        if (stored && stored.createdAt === entry.createdAt) {
            twoFactorStore.delete(userId);
        }
    }, CODE_EXPIRATION_MS);

    return entry;
}

// Verify a 2FA code
function verifyCode(userId, inputCode) {
    const entry = twoFactorStore.get(userId);

    if (!entry) {
        return { success: false, error: 'No verification code found. Please request a new code.' };
    }

    if (entry.verified) {
        return { success: false, error: 'Code has already been used. Please request a new code.' };
    }

    if (Date.now() - entry.createdAt > CODE_EXPIRATION_MS) {
        twoFactorStore.delete(userId);
        return { success: false, error: 'Verification code has expired. Please request a new code.' };
    }

    if (entry.attempts >= MAX_ATTEMPTS) {
        twoFactorStore.delete(userId);
        return { success: false, error: 'Maximum verification attempts exceeded. Please request a new code.' };
    }

    entry.attempts += 1;

    // Timing-safe comparison to prevent timing attacks
    const inputBuffer = Buffer.from(inputCode.padEnd(6, '0'));
    const codeBuffer = Buffer.from(entry.code.padEnd(6, '0'));

    if (inputCode.length === 6 && crypto.timingSafeEqual(inputBuffer, codeBuffer)) {
        entry.verified = true;
        return { success: true, message: 'Code verified successfully.' };
    }

    const remainingAttempts = MAX_ATTEMPTS - entry.attempts;
    return {
        success: false,
        error: `Invalid code. ${remainingAttempts} attempt(s) remaining.`
    };
}

// Send SMS via Twilio
async function sendSMS(phoneNumber, code) {
    try {
        const message = await twilioClient.messages.create({
            body: `Your verification code is: ${code}. This code expires in 5 minutes. Do not share this code with anyone.`,
            from: TWILIO_PHONE_NUMBER,
            to: phoneNumber
        });
        console.log(`SMS sent successfully. SID: ${message.sid}`);
        return { success: true, messageSid: message.sid };
    } catch (error) {
        console.error('Failed to send SMS:', error.message);
        return { success: false, error: error.message };
    }
}

// Middleware to check if user is authenticated (first factor)
function requireFirstFactor(req, res, next) {
    if (!req.session.userId || !req.session.firstFactorComplete) {
        return res.status(401).json({ error: 'Please complete the first authentication step.' });
    }
    next();
}

// Middleware to check if user is fully authenticated
function requireFullAuth(req, res, next) {
    if (!req.session.userId || !req.session.fullyAuthenticated) {
        return res.status(401).json({ error: 'Full authentication required.' });
    }
    next();
}

// Cleanup expired entries periodically
setInterval(() => {
    const now = Date.now();
    for (const [userId, entry] of twoFactorStore.entries()) {
        if (now - entry.createdAt > CODE_EXPIRATION_MS) {
            twoFactorStore.delete(userId);
        }
    }

    for (const [phone, timestamps] of rateLimitStore.entries()) {
        const valid = timestamps.filter(ts => now - ts < RATE_LIMIT_WINDOW_MS);
        if (valid.length === 0) {
            rateLimitStore.delete(phone);
        } else {
            rateLimitStore.set(phone, valid);
        }
    }
}, 60 * 1000);

